// ============================================================
// AGENDA DIARIA 5:35 AM — LUIS DANIEL / MYSTIC AI OS
// Marco / Sonora Digital Corp
// ============================================================

const now = new Date();

// --- Fecha ---
const opcionesFecha = {
  weekday: 'long',
  year: 'numeric',
  month: 'long',
  day: 'numeric',
  timeZone: 'America/Hermosillo'
};
const fechaTexto = now.toLocaleDateString('es-MX', opcionesFecha);
const diaSemana = now.toLocaleDateString('es-MX', { weekday: 'long', timeZone: 'America/Hermosillo' }).toLowerCase();
const diaNum = now.getDay(); // 0=domingo, 1=lunes, ..., 6=sábado

// --- Bloques de tiempo fijos ---
const bloques = [
  { hora: '6:00 - 8:00 AM',  emoji: '🏃', nombre: 'Cuerpo y Mente',        actividad: 'Ejercicio físico (45 min) + Meditación (15 min) + Ducha fría + Desayuno nutritivo' },
  { hora: '8:00 - 10:00 AM', emoji: '💻', nombre: 'Deep Work MYSTIC I',     actividad: 'Desarrollo concentrado — sin interrupciones, modo avión activado. 2 horas de máxima productividad.' },
  { hora: '10:00 - 12:00 PM',emoji: '📞', nombre: 'Ventas y Clientes',      actividad: 'Llamadas a prospectos, demos de MYSTIC, seguimiento CRM, cierre de tratos.' },
  { hora: '12:00 - 1:00 PM', emoji: '🥗', nombre: 'Almuerzo + Recarga',     actividad: 'Come lejos de la pantalla. Camina 10 min. Respira. Tu cerebro necesita este reset.' },
  { hora: '1:00 - 3:00 PM',  emoji: '⚙️', nombre: 'Deep Work MYSTIC II',   actividad: 'Sprint de desarrollo o arquitectura. Implementar lo planificado en la mañana.' },
  { hora: '3:00 - 5:00 PM',  emoji: '📊', nombre: 'Admin y Finanzas',       actividad: 'Facturas, cuentas por cobrar, revisión de gastos, correos operativos, tareas administrativas.' },
  { hora: '5:00 - 7:00 PM',  emoji: '📚', nombre: 'Academia y Crecimiento', actividad: 'Curso, lectura técnica, video educativo o práctica de nueva habilidad. Invierte en tu futuro.' },
  { hora: '7:00 - 9:00 PM',  emoji: '❤️', nombre: 'Familia y Descanso',    actividad: 'Tiempo de calidad con familia. Sin trabajo. Presencia total. Recarga emocional.' }
];

// --- Tarea principal + 3 metas por día de semana ---
const planSemana = {
  lunes: {
    emoji: '📋',
    tarea_principal: 'PLANIFICACIÓN SEMANAL MYSTIC',
    descripcion: 'Define el sprint de la semana. Revisa backlog, prioriza features, asigna tareas. La claridad del lunes define el éxito del viernes.',
    metas: [
      '✅ Actualizar el tablero de tareas con prioridades de la semana',
      '✅ Revisar métricas de la semana anterior (usuarios, conversiones, uptime)',
      '✅ Hacer 3 llamadas a prospectos o clientes activos'
    ],
    consejo: 'El lunes bien planificado vale 3 días de trabajo reactivo.'
  },
  martes: {
    emoji: '⚙️',
    tarea_principal: 'SPRINT DE DESARROLLO',
    descripcion: 'Día de código puro. Features del roadmap, corrección de bugs críticos, mejoras de arquitectura. Minimaliza reuniones.',
    metas: [
      '✅ Completar al menos 1 feature o fix crítico en MYSTIC',
      '✅ Hacer commit y deploy a staging si procede',
      '✅ Documentar lo construido en el task board'
    ],
    consejo: 'El código que no se deploya no existe. Construye, prueba, lanza.'
  },
  miércoles: {
    emoji: '🤝',
    tarea_principal: 'DÍA DE VENTAS Y DEMOS',
    descripcion: 'El miércoles es el centro de la semana laboral. Máxima energía para cerrar tratos, hacer demos y expandir la red de MYSTIC.',
    metas: [
      '✅ Realizar al menos 1 demo de MYSTIC a un prospecto calificado',
      '✅ Seguimiento a todos los leads en pipeline (responder mensajes, emails)',
      '✅ Agregar 2 nuevos prospectos al CRM'
    ],
    consejo: 'Cada NO es datos. Cada SÍ es crecimiento. El miércoles no termina sin haber vendido.'
  },
  jueves: {
    emoji: '🔁',
    tarea_principal: 'OPERACIONES Y RETENCIÓN',
    descripcion: 'Cuida lo que ya tienes. Clientes activos, soporte, calidad de servicio. Un cliente feliz vale 10 nuevos prospectos.',
    metas: [
      '✅ Revisar y resolver todos los tickets de soporte abiertos',
      '✅ Check-in con al menos 1 cliente activo (llamada o mensaje)',
      '✅ Revisar uptime y performance de MYSTIC en producción'
    ],
    consejo: 'La retención es el nuevo crecimiento. Un cliente que renueva es una victoria.'
  },
  viernes: {
    emoji: '🚀',
    tarea_principal: 'DEPLOY, REVIEW Y CIERRE',
    descripcion: 'Día de resultados. Lanza lo construido, revisa las métricas de la semana, documenta aprendizajes y prepara el lunes siguiente.',
    metas: [
      '✅ Deploy de todo lo que está listo a producción',
      '✅ Revisar KPIs de la semana y registrarlos',
      '✅ Escribir 3 aprendizajes clave de la semana en el diario'
    ],
    consejo: 'El viernes bien cerrado es el lunes bien empezado. No arrastres deuda a la semana siguiente.'
  },
  sábado: {
    emoji: '🧠',
    tarea_principal: 'APRENDIZAJE PROFUNDO Y EXPLORACIÓN',
    descripcion: 'El sábado es para construir el siguiente nivel de ti mismo. Lee, estudia, experimenta sin presión de resultados inmediatos.',
    metas: [
      '✅ Completar al menos 1 hora de curso o lectura técnica relevante',
      '✅ Explorar 1 tecnología nueva o herramienta que pueda mejorar MYSTIC',
      '✅ Escribir en el diario: ¿qué aprendiste esta semana que cambió tu visión?'
    ],
    consejo: 'El CEO que deja de aprender empieza a obsoletarse. El sábado es tu ventaja competitiva intelectual.'
  },
  domingo: {
    emoji: '❤️',
    tarea_principal: 'FAMILIA, RECARGA Y VISIÓN',
    descripcion: 'El domingo no es para trabajar, es para recargar. Un CEO descansado toma mejores decisiones el lunes.',
    metas: [
      '✅ Desconéctate del trabajo por completo (sin Slack, sin código)',
      '✅ Tiempo de calidad con familia — actividad especial juntos',
      '✅ 15 minutos de reflexión: ¿estoy alineado con mi visión de vida?'
    ],
    consejo: 'La productividad sostenible requiere recuperación profunda. El descanso es parte de la estrategia.'
  }
};

const planHoy = planSemana[diaSemana] || planSemana['lunes'];

// --- Valores y visión (rotativos) ---
const valores = [
  '🌟 *Visión*: Ser la plataforma contable #1 para PYMEs mexicanas en 3 años.',
  '💪 *Misión*: Automatizar la contabilidad para que los empresarios se enfoquen en crecer.',
  '🔥 *Valor 1*: Excelencia — MYSTIC hace en segundos lo que tarda horas manualmente.',
  '🤝 *Valor 2*: Confianza — Los datos financieros de nuestros clientes son sagrados.',
  '🚀 *Valor 3*: Velocidad — El mercado no espera. Nosotros tampoco.',
  '🧠 *Valor 4*: Inteligencia — Usamos IA donde agrega valor real, no como gimmick.',
  '❤️ *Valor 5*: Familia — El éxito sin familia no es éxito.'
];
const diaDelAno = Math.floor((now - new Date(now.getFullYear(), 0, 0)) / 86400000);
const valorHoy = valores[diaDelAno % valores.length];

// --- Numero de semana del año ---
const primerDiaAno = new Date(now.getFullYear(), 0, 1);
const numSemana = Math.ceil(((now - primerDiaAno) / 86400000 + primerDiaAno.getDay() + 1) / 7);

// --- Construir agenda en Markdown ---
const agenda = `📅 *AGENDA DEL DÍA — LUIS DANIEL*
━━━━━━━━━━━━━━━━━━━━━━
🗓 *${fechaTexto.charAt(0).toUpperCase() + fechaTexto.slice(1)}*
📊 Semana ${numSemana} del año

━━━━━━━━━━━━━━━━━━━━━━
${planHoy.emoji} *TAREA PRINCIPAL: ${planHoy.tarea_principal}*
━━━━━━━━━━━━━━━━━━━━━━
${planHoy.descripcion}

*Tus 3 metas de hoy:*
${planHoy.metas.join('\n')}

💡 _${planHoy.consejo}_

━━━━━━━━━━━━━━━━━━━━━━
⏰ *TU AGENDA HOY*
━━━━━━━━━━━━━━━━━━━━━━
${bloques.map(b => `${b.emoji} *${b.hora}*\n   ${b.nombre}\n   _${b.actividad}_`).join('\n\n')}

━━━━━━━━━━━━━━━━━━━━━━
${valorHoy}
━━━━━━━━━━━━━━━━━━━━━━
_MYSTIC AI OS — Construyendo el futuro hoy_
🚀 *¡Que sea un día extraordinario!*`;

return [{
  json: {
    agenda,
    tarea_principal: planHoy.tarea_principal,
    dia_semana: diaSemana,
    semana: numSemana,
    fecha: fechaTexto
  }
}];
